        .Where(f => f.Contains("3.2.2"))
        .FirstOrDefault();
    if (found != null) return context.LoadFromAssemblyPath(found);
    return null;
};

var coreDll = System.IO.Path.Combine(basePath, "xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll");
var asm = ctx.LoadFromAssemblyPath(coreDll);

