using System;
using System.Linq;
using System.Reflection;
using System.Reflection.Metadata;
using System.Reflection.PortableExecutable;

var home = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
var coreDll = System.IO.Path.Combine(home, ".nuget/packages/xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll");

using var fs = System.IO.File.OpenRead(coreDll);
using var pe = new PEReader(fs);
var mr = pe.GetMetadataReader();

foreach (var tdh in mr.TypeDefinitions) {
